"""Flask-style API handlers.

Endpoints use the field names from models.py in request/response JSON.
"""
from flask import Flask, request, jsonify
from db import create_user, get_user, update_user, create_order, \
    get_orders_for_user, get_order_total

app = Flask(__name__)


@app.route("/users", methods=["POST"])
def post_user():
    """Create a new user."""
    data = request.get_json()
    missing = []
    for field in ["first_name", "last_name", "email_addr"]:
        if field not in data:
            missing.append(field)
    if missing:
        return jsonify({"error": f"Missing fields: {missing}"}), 400

    user = create_user(
        first_name=data["first_name"],
        last_name=data["last_name"],
        email_addr=data["email_addr"],
        is_active=data.get("is_active", 1),
    )
    return jsonify(user), 201


@app.route("/users/<int:user_id>", methods=["GET"])
def get_user_route(user_id):
    """Fetch a single user."""
    user = get_user(user_id)
    if user is None:
        return jsonify({"error": "User not found"}), 404
    return jsonify(user)


@app.route("/users/<int:user_id>", methods=["PATCH"])
def patch_user(user_id):
    """Update user fields."""
    data = request.get_json()
    user = update_user(user_id, **data)
    if user is None:
        return jsonify({"error": "User not found"}), 404
    return jsonify(user)


@app.route("/orders", methods=["POST"])
def post_order():
    """Create a new order."""
    data = request.get_json()
    required = ["user_id", "item_name", "item_price", "qty"]
    missing = [f for f in required if f not in data]
    if missing:
        return jsonify({"error": f"Missing fields: {missing}"}), 400

    order = create_order(
        user_id=data["user_id"],
        item_name=data["item_name"],
        item_price=data["item_price"],
        qty=data["qty"],
    )
    return jsonify(order), 201


@app.route("/users/<int:user_id>/orders", methods=["GET"])
def get_user_orders(user_id):
    """Fetch all orders for a user."""
    orders = get_orders_for_user(user_id)
    return jsonify({"user_id": user_id, "orders": orders})


@app.route("/users/<int:user_id>/total", methods=["GET"])
def get_user_total(user_id):
    """Get total spend for a user."""
    total = get_order_total(user_id)
    return jsonify({"user_id": user_id, "total": total})


if __name__ == "__main__":
    app.run(debug=True, port=5000)

