"""Input validation using the record schemas from models.py."""
from models import USER_FIELDS, ORDER_FIELDS, USER_AUTO_FIELDS, ORDER_AUTO_FIELDS


def validate_user_input(data: dict) -> list[str]:
    """Validate user creation input.

    Returns a list of error messages (empty if valid).
    """
    errors = []
    required = {k for k in USER_FIELDS if k not in USER_AUTO_FIELDS}
    for field_name in required:
        if field_name not in data:
            errors.append(f"Missing required field: {field_name}")
            continue
        expected_type = USER_FIELDS[field_name]
        if not isinstance(data[field_name], expected_type):
            errors.append(
                f"Field '{field_name}' must be {expected_type.__name__}, "
                f"got {type(data[field_name]).__name__}"
            )
    # Extra check: is_active must be 0 or 1
    if "is_active" in data and data["is_active"] not in (0, 1):
        errors.append("is_active must be 0 or 1")
    return errors


def validate_order_input(data: dict) -> list[str]:
    """Validate order creation input.

    Returns a list of error messages (empty if valid).
    """
    errors = []
    required = {k for k in ORDER_FIELDS if k not in ORDER_AUTO_FIELDS}
    for field_name in required:
        if field_name not in data:
            errors.append(f"Missing required field: {field_name}")
            continue
        expected_type = ORDER_FIELDS[field_name]
        if not isinstance(data[field_name], expected_type):
            errors.append(
                f"Field '{field_name}' must be {expected_type.__name__}, "
                f"got {type(data[field_name]).__name__}"
            )
    # Extra check: qty must be positive
    if "qty" in data and data["qty"] < 1:
        errors.append("qty must be at least 1")
    # Extra check: item_price must be non-negative
    if "item_price" in data and data["item_price"] < 0:
        errors.append("item_price cannot be negative")
    return errors
